import { GoogleGenAI, Type } from "@google/genai";
import { FuelStation } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getFuelAdvisor = async (stations: FuelStation[], query: string) => {
  try {
    const context = stations.map(s => 
      `${s.name} em ${s.neighborhood}: Gasolina está ${s.gasolineStatus}, Gasóleo está ${s.dieselStatus}`
    ).join('. ');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Contexto dos postos de combustível no Soyo: ${context}. Pergunta do usuário: ${query}`,
      config: {
        systemInstruction: "Você é o assistente do app Fuel Check Soyo. Ajude o usuário a encontrar combustível de forma rápida e educada em português de Angola. Seja breve e direto.",
        temperature: 0.7,
      }
    });

    return response.text || "Não consegui processar seu pedido agora. Verifique a lista abaixo.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Ocorreu um erro ao consultar o assistente.";
  }
};

import React from 'react';
import { FuelStation, FuelStatus } from '../types';

interface Props {
  station: FuelStation;
}

const StatusBadge = ({ status, label }: { status: FuelStatus, label: string }) => {
  const configs = {
    [FuelStatus.AVAILABLE]: { bg: 'bg-green-100', text: 'text-green-700', dot: 'bg-green-500', msg: 'Disponível' },
    [FuelStatus.LOW]: { bg: 'bg-yellow-100', text: 'text-yellow-700', dot: 'bg-yellow-500', msg: 'Pouco Stock' },
    [FuelStatus.UNAVAILABLE]: { bg: 'bg-red-100', text: 'text-red-700', dot: 'bg-red-500', msg: 'Esgotado' }
  };

  const config = configs[status];

  return (
    <div className={`flex flex-col gap-1 p-2 rounded-lg ${config.bg} border border-opacity-20`}>
      <span className="text-[10px] uppercase font-bold text-gray-500">{label}</span>
      <div className="flex items-center gap-2">
        <div className={`w-2 h-2 rounded-full ${config.dot} animate-pulse`}></div>
        <span className={`text-sm font-semibold ${config.text}`}>{config.msg}</span>
      </div>
    </div>
  );
};

