        <div className="space-y-1">
          <label className="text-sm font-semibold text-gray-700 ml-1">Nome da Empresa / Posto</label>
          <input 
            required
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none"
