      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700 ml-1">Nome Completo</label>
            <input 
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none"
              placeholder="Ex: João Baptista"
              value={formData.fullName}
              onChange={e => setFormData({...formData, fullName: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700 ml-1">Nome do Posto</label>
            <input 
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none"
              placeholder="Ex: Sonangol Soyo"
              value={formData.companyName}
              onChange={e => setFormData({...formData, companyName: e.target.value})}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700 ml-1">Telefone</label>
            <input 
              required
              type="tel"
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none"
              placeholder="+244"
              value={formData.phone}
              onChange={e => setFormData({...formData, phone: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700 ml-1">E-mail de Contacto</label>
            <input 
              required
              type="email"
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none"
              placeholder="empresa@exemplo.com"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700 ml-1">Nº NIF</label>
            <input required className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none" value={formData.nif} onChange={e => setFormData({...formData, nif: e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700 ml-1">Nº Bilhete (BI)</label>
            <input required className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none" value={formData.biNumber} onChange={e => setFormData({...formData, biNumber: e.target.value})}/>
