            {SOYO_NEIGHBORHOODS.map(n => <option key={n} value={n}>{n}</option>)}
          </select>
        </div>

        <div className="border-t border-gray-100 pt-6">
          <h3 className="text-sm font-bold text-[#0c3a4a] mb-4 uppercase tracking-wider">Documentação Obrigatória</h3>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <FileInput label="Cópia do BI" id="bi" onChange={(f) => setFiles({...files, bi: f})} />
            <FileInput label="Cartão de NIF" id="nif" onChange={(f) => setFiles({...files, nif: f})} />
            <FileInput label="Documento Legal" id="legal" onChange={(f) => setFiles({...files, legal: f})} />
          </div>
          <p className="text-[10px] text-gray-400 mt-2">* Os documentos serão enviados para análise do administrador.</p>
        </div>

        <div className="flex gap-4 pt-4">
          <button 
            type="button"
            onClick={onCancel}
            disabled={isSubmitting}
            className="flex-1 px-6 py-4 rounded-2xl border border-gray-200 text-gray-600 font-bold hover:bg-gray-50 transition-all disabled:opacity-50"
          >
            Cancelar
          </button>
          <button 
            type="submit"
