import React, { useState } from 'react';
import { BusinessOwner } from '../types';
import { SOYO_NEIGHBORHOODS, ADMIN_EMAIL } from '../constants';

interface Props {
  onRegister: (data: BusinessOwner) => void;
  onCancel: () => void;
}

export const RegistrationForm: React.FC<Props> = ({ onRegister, onCancel }) => {
  const [formData, setFormData] = useState<BusinessOwner>({
    fullName: '',
    phone: '',
    email: '',
    nif: '',
    biNumber: '',
    neighborhood: SOYO_NEIGHBORHOODS[0],
    companyName: ''
  });

  const [files, setFiles] = useState({
    bi: null as File | null,
    nif: null as File | null,
    legal: null as File | null
  });

  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!files.bi || !files.nif || !files.legal) {
      alert("Por favor, carregue todos os documentos obrigatórios.");
      return;
    }

    setIsSubmitting(true);

    // Preparar os dados para o FormSubmit
    const formPayload = new FormData();
    formPayload.append('Nome Completo', formData.fullName);
    formPayload.append('Empresa', formData.companyName);
    formPayload.append('Telefone', formData.phone);
    formPayload.append('Email de Contacto', formData.email);
    formPayload.append('NIF', formData.nif);
    formPayload.append('BI', formData.biNumber);
    formPayload.append('Bairro', formData.neighborhood);

    // Anexar ficheiros (FormSubmit aceita anexos)
    if (files.bi) formPayload.append('Documento_BI', files.bi);
    if (files.nif) formPayload.append('Documento_NIF', files.nif);
    if (files.legal) formPayload.append('Documento_Legal', files.legal);

    // Configurações do FormSubmit
    formPayload.append('_subject', `Novo Registo de Posto: ${formData.companyName}`);
    formPayload.append('_template', 'table');
    formPayload.append('_captcha', 'false');

    try {
      const response = await fetch(`https://formsubmit.co/ajax/${ADMIN_EMAIL}`, {
        method: 'POST',
        body: formPayload
      });

      if (response.ok) {
        onRegister({
          ...formData,
          documents: {
            biFile: files.bi?.name || '',
            nifFile: files.nif?.name || '',
            legalFile: files.legal?.name || ''
          }
        });
      } else {
        throw new Error('Falha ao enviar e-mail');
      }
    } catch (error) {
      console.error("Erro no envio:", error);
      alert("Erro ao enviar os documentos. Por favor, tente novamente ou contacte o suporte.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const FileInput = ({ label, id, onChange }: { label: string, id: string, onChange: (f: File | null) => void }) => (
    <div className="space-y-1">
      <label className="text-sm font-semibold text-gray-700 ml-1">{label} *</label>
      <div className="relative border-2 border-dashed border-gray-200 rounded-xl p-4 hover:border-[#08677a] transition-all bg-gray-50 flex flex-col items-center justify-center cursor-pointer">
        <input 
          type="file" 
          id={id} 
          name={id}
          required 
          className="absolute inset-0 opacity-0 cursor-pointer" 
          onChange={(e) => onChange(e.target.files?.[0] || null)}
        />
        <svg className="w-6 h-6 text-gray-400 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
        </svg>
        <span className="text-[10px] text-gray-500 text-center truncate max-w-full px-2">
          {id === 'bi' && files.bi ? files.bi.name : 
           id === 'nif' && files.nif ? files.nif.name : 
           id === 'legal' && files.legal ? files.legal.name : 'Selecionar ficheiro'}
        </span>
      </div>
    </div>
  );

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-3xl shadow-xl border border-gray-100">
