import React, { useState } from 'react';
import { BusinessOwner } from '../types';
import { SOYO_NEIGHBORHOODS, ADMIN_EMAIL } from '../constants';

interface Props {
  onRegister: (data: BusinessOwner) => void;
  onCancel: () => void;
}

export const RegistrationForm: React.FC<Props> = ({ onRegister, onCancel }) => {
  const [formData, setFormData] = useState<BusinessOwner>({
    fullName: '',
    phone: '',
    email: '',
    nif: '',
    biNumber: '',
    neighborhood: SOYO_NEIGHBORHOODS[0],
    companyName: ''
  });

  const [files, setFiles] = useState({
    bi: null as File | null,
    nif: null as File | null,
    legal: null as File | null
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showErrors, setShowErrors] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validação manual robusta
    if (!files.bi || !files.nif || !files.legal) {
      setShowErrors(true);
      alert("Atenção: Todos os documentos (BI, NIF e Alvará) são obrigatórios para a análise.");
      return;
    }

    setIsSubmitting(true);

    try {
      // Usando FormData para enviar ficheiros e texto
      const formPayload = new FormData();

      // Cabeçalhos e Configurações FormSubmit
      formPayload.append('_subject', `NOVO REGISTO: ${formData.companyName} - Soyo`);
      formPayload.append('_template', 'table');
      formPayload.append('_captcha', 'false');

      // Dados do Proprietário
      formPayload.append('Proprietário', formData.fullName);
      formPayload.append('Empresa/Posto', formData.companyName);
      formPayload.append('Telefone', formData.phone);
      formPayload.append('Email de Contacto', formData.email);
      formPayload.append('NIF Número', formData.nif);
      formPayload.append('BI Número', formData.biNumber);
      formPayload.append('Bairro', formData.neighborhood);

      // Ficheiros Reais
      formPayload.append('Anexo_BI', files.bi);
      formPayload.append('Anexo_NIF', files.nif);
      formPayload.append('Anexo_Alvara_Comercial', files.legal);

      const response = await fetch(`https://formsubmit.co/ajax/${ADMIN_EMAIL}`, {
        method: 'POST',
        body: formPayload
      });

      if (response.ok) {
        onRegister({
          ...formData,
          documents: {
            biFile: files.bi.name,
            nifFile: files.nif.name,
            legalFile: files.legal.name
          }
        });
      } else {
        const errorData = await response.json();
        console.error("Erro FormSubmit:", errorData);
        throw new Error('Falha no serviço de e-mail');
      }
    } catch (error) {
      console.error("Erro no envio:", error);
      alert("Erro ao enviar para o e-mail. Verifique a sua ligação à internet ou tente novamente.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const FileInput = ({ label, id, file, onChange }: { label: string, id: string, file: File | null, onChange: (f: File | null) => void }) => {
    const hasError = showErrors && !file;

    return (
      <div className="space-y-1">
        <label className="text-[11px] font-bold text-gray-500 ml-1 uppercase">{label} *</label>
        <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all flex flex-col items-center justify-center cursor-pointer min-h-[100px] ${
          file ? 'border-green-400 bg-green-50' : 
          hasError ? 'border-red-400 bg-red-50' : 'border-gray-200 bg-gray-50 hover:border-[#08677a]'
        }`}>
          <input 
            type="file" 
            id={id} 
            className="absolute inset-0 opacity-0 cursor-pointer" 
            onChange={(e) => {
              const selectedFile = e.target.files?.[0] || null;
              onChange(selectedFile);
            }}
          />
          {file ? (
            <svg className="w-6 h-6 text-green-500 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
            </svg>
          ) : (
            <svg className={`w-6 h-6 mb-1 ${hasError ? 'text-red-400' : 'text-gray-400'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
            </svg>
          )}
          <span className={`text-[10px] text-center px-2 font-medium ${file ? 'text-green-700' : hasError ? 'text-red-500' : 'text-gray-400'}`}>
            {file ? file.name : 'Tocar para carregar'}
          </span>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-2xl mx-auto bg-white p-6 sm:p-8 rounded-3xl shadow-xl border border-gray-100">
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-black text-[#0c3a4a]">Registo do Posto</h2>
        <p className="text-gray-500 text-sm mt-1">Soyo Digital - Painel de Administrador</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-600">Nome do Responsável</label>
            <input 
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none text-sm"
              placeholder="Ex: Miguel Filipe"
              value={formData.fullName}
              onChange={e => setFormData({...formData, fullName: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-600">Nome da Bomba/Posto</label>
            <input 
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none text-sm"
              placeholder="Ex: Sonangol Soyo Centro"
              value={formData.companyName}
              onChange={e => setFormData({...formData, companyName: e.target.value})}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-600">Telemóvel</label>
            <input 
              required
              type="tel"
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none text-sm"
              placeholder="+244"
              value={formData.phone}
              onChange={e => setFormData({...formData, phone: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-600">E-mail</label>
            <input 
              required
              type="email"
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none text-sm"
              placeholder="contato@empresa.com"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-600">NIF da Empresa</label>
            <input required className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none text-sm uppercase" value={formData.nif} onChange={e => setFormData({...formData, nif: e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-600">Nº do Bilhete (BI)</label>
            <input required className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#08677a] outline-none text-sm uppercase" value={formData.biNumber} onChange={e => setFormData({...formData, biNumber: e.target.value})}/>
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-xs font-bold text-gray-600">Localização no Soyo</label>
          <select 
            className="w-full px-4 py-3 rounded-xl border border-gray-200 outline-none bg-white text-sm"
            value={formData.neighborhood}
            onChange={e => setFormData({...formData, neighborhood: e.target.value})}
          >
            {SOYO_NEIGHBORHOODS.map(n => <option key={n} value={n}>{n}</option>)}
          </select>
        </div>

        <div className="bg-gray-50 p-5 rounded-2xl border border-gray-100">
          <h3 className="text-xs font-black text-[#0c3a4a] mb-4 uppercase tracking-widest text-center">Enviar Documentos para Miguel</h3>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            <FileInput label="BI" id="bi" file={files.bi} onChange={(f) => setFiles({...files, bi: f})} />
            <FileInput label="NIF" id="nif" file={files.nif} onChange={(f) => setFiles({...files, nif: f})} />
            <FileInput label="Alvará" id="legal" file={files.legal} onChange={(f) => setFiles({...files, legal: f})} />
          </div>
        </div>

        <div className="flex flex-col gap-3 pt-2">
          <button 
            type="submit"
            disabled={isSubmitting}
            className="w-full px-6 py-4 rounded-2xl bg-[#08677a] text-white font-bold hover:bg-[#0c3a4a] shadow-lg shadow-teal-100 transition-all disabled:opacity-50 flex items-center justify-center gap-3"
          >
            {isSubmitting ? (
              <>
                <div className="w-5 h-5 border-3 border-white border-t-transparent rounded-full animate-spin"></div>
                A ENVIAR PARA O EMAIL...
              </>
            ) : 'FINALIZAR E ENVIAR'}
          </button>
          <button 
            type="button"
            onClick={onCancel}
            className="w-full py-3 text-gray-400 font-bold text-sm hover:text-gray-600 transition-colors"
          >
            Cancelar Registo
          </button>
        </div>
      </form>
    </div>
  );
};

