import React, { useState } from 'react';
import { BusinessOwner } from '../types';
import { SOYO_NEIGHBORHOODS, ADMIN_EMAIL, ADMIN_WHATSAPP } from '../constants';

interface Props {
  onRegister: (data: BusinessOwner) => void;
  onCancel: () => void;
}

export const RegistrationForm: React.FC<Props> = ({ onRegister, onCancel }) => {
  const [formData, setFormData] = useState<BusinessOwner>({
    fullName: '',
    phone: '',
    email: '',
    nif: '',
    biNumber: '',
    neighborhood: SOYO_NEIGHBORHOODS[0],
    companyName: ''
  });

  const [files, setFiles] = useState({
    bi: null as File | null,
    nif: null as File | null,
    legal: null as File | null
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showErrors, setShowErrors] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!files.bi || !files.nif || !files.legal) {
      setShowErrors(true);
      alert("Atenção: É necessário carregar as fotos dos 3 documentos para prosseguir.");
      return;
    }

    setIsSubmitting(true);

    try {
      // 1. Enviar para E-mail via FormSubmit
      const formPayload = new FormData();
      formPayload.append('_subject', `NOVO REGISTO: ${formData.companyName} (${formData.fullName})`);
      formPayload.append('Nome Completo', formData.fullName);
      formPayload.append('Posto/Empresa', formData.companyName);
      formPayload.append('Telefone', formData.phone);
      formPayload.append('Email', formData.email);
      formPayload.append('NIF', formData.nif);
      formPayload.append('BI', formData.biNumber);
      formPayload.append('Bairro', formData.neighborhood);
      formPayload.append('Anexo_BI', files.bi);
      formPayload.append('Anexo_NIF', files.nif);
      formPayload.append('Anexo_Alvara', files.legal);

      // Envio AJAX para e-mail
      await fetch(`https://formsubmit.co/ajax/${ADMIN_EMAIL}`, {
        method: 'POST',
        body: formPayload
      });

      // 2. Preparar mensagem para WhatsApp
      const waMessage = `*NOVO REGISTO DE POSTO - FUEL CHECK SOYO*%0A%0A` +
        `*Dono:* ${formData.fullName}%0A` +
        `*Empresa:* ${formData.companyName}%0A` +
        `*Email:* ${formData.email}%0A` +
        `*Telefone:* ${formData.phone}%0A` +
        `*NIF:* ${formData.nif}%0A` +
        `*BI:* ${formData.biNumber}%0A` +
        `*Bairro:* ${formData.neighborhood}%0A%0A` +
        `*Documentos enviados:*%0A` +
        `- BI: ${files.bi.name}%0A` +
        `- NIF: ${files.nif.name}%0A` +
        `- Alvará: ${files.legal.name}%0A%0A` +
        `_Clique no link abaixo para aprovar este usuário:_ %0A` +
        `${window.location.origin}?login=${encodeURIComponent(formData.email)}`;

      // 3. Abrir WhatsApp
      const waUrl = `https://wa.me/${ADMIN_WHATSAPP}?text=${waMessage}`;
      window.open(waUrl, '_blank');

      // Finalizar processo no app
      onRegister({
        ...formData,
        documents: {
          biFile: files.bi.name,
          nifFile: files.nif.name,
          legalFile: files.legal.name
        }
      });

    } catch (error) {
      console.error("Erro no envio:", error);
      alert("Ocorreu um erro ao enviar os dados. Por favor, tente novamente.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const FileInput = ({ label, id, file, onChange }: { label: string, id: string, file: File | null, onChange: (f: File | null) => void }) => {
    const hasError = showErrors && !file;
    return (
      <div className="space-y-1">
        <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">{label}</label>
        <div 
          onClick={() => document.getElementById(`file-${id}`)?.click()}
          className={`relative border-2 border-dashed rounded-2xl p-4 transition-all flex flex-col items-center justify-center min-h-[90px] cursor-pointer ${
            file ? 'border-green-400 bg-green-50' : 
            hasError ? 'border-red-400 bg-red-50' : 'border-gray-200 bg-gray-50'
          }`}
        >
          <input 
            type="file" 
            id={`file-${id}`} 
            className="hidden" 
            onChange={(e) => onChange(e.target.files?.[0] || null)}
          />
          <svg className={`w-6 h-6 mb-1 ${file ? 'text-green-500' : hasError ? 'text-red-400' : 'text-gray-300'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
            {file ? (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
            ) : (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
            )}
          </svg>
          <span className={`text-[10px] text-center font-bold truncate max-w-full px-2 ${file ? 'text-green-700' : hasError ? 'text-red-500' : 'text-gray-400'}`}>
            {file ? file.name : 'Subir Foto'}
          </span>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-2xl mx-auto bg-white p-6 sm:p-8 rounded-3xl shadow-xl border border-gray-100 animate-in fade-in zoom-in-95 duration-300">
      <div className="mb-8 text-center">
        <div className="w-16 h-16 bg-[#08677a]/10 rounded-full flex items-center justify-center mx-auto mb-3">
          <svg className="w-8 h-8 text-[#08677a]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
          </svg>
        </div>
        <h2 className="text-2xl font-black text-[#0c3a4a]">Cadastro de Parceiro</h2>
        <p className="text-gray-500 text-sm mt-1">Os dados serão enviados para o WhatsApp e E-mail do Administrador.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <input required placeholder="Nome do Responsável" className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 focus:ring-2 focus:ring-[#08677a] outline-none text-sm" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})}/>
          <input required placeholder="Nome do Posto (Bomba)" className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 focus:ring-2 focus:ring-[#08677a] outline-none text-sm" value={formData.companyName} onChange={e => setFormData({...formData, companyName: e.target.value})}/>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <input required type="tel" placeholder="Nº de Telemóvel" className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 focus:ring-2 focus:ring-[#08677a] outline-none text-sm" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})}/>
          <input required type="email" placeholder="E-mail" className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 focus:ring-2 focus:ring-[#08677a] outline-none text-sm" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})}/>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <input required placeholder="NIF Empresa" className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 focus:ring-2 focus:ring-[#08677a] outline-none text-sm uppercase" value={formData.nif} onChange={e => setFormData({...formData, nif: e.target.value})}/>
          <input required placeholder="Nº Bilhete de Identidade" className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 focus:ring-2 focus:ring-[#08677a] outline-none text-sm uppercase" value={formData.biNumber} onChange={e => setFormData({...formData, biNumber: e.target.value})}/>
        </div>

        <div className="space-y-1">
          <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">Localização no Soyo</label>
          <select className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 outline-none text-sm" value={formData.neighborhood} onChange={e => setFormData({...formData, neighborhood: e.target.value})}>
            {SOYO_NEIGHBORHOODS.map(n => <option key={n} value={n}>{n}</option>)}
          </select>
        </div>

        <div className="pt-2">
          <h3 className="text-xs font-black text-[#0c3a4a] mb-3 uppercase tracking-wider">Documentação Digitalizada</h3>
          <div className="grid grid-cols-3 gap-3">
            <FileInput label="BI" id="bi" file={files.bi} onChange={(f) => setFiles({...files, bi: f})} />
            <FileInput label="NIF" id="nif" file={files.nif} onChange={(f) => setFiles({...files, nif: f})} />
            <FileInput label="Alvará" id="legal" file={files.legal} onChange={(f) => setFiles({...files, legal: f})} />
          </div>
        </div>

        <div className="flex flex-col gap-3 pt-4">
          <button 
            type="submit" 
            disabled={isSubmitting}
            className="w-full py-4 rounded-2xl bg-[#08677a] text-white font-black hover:bg-[#0c3a4a] shadow-xl shadow-teal-100 transition-all disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {isSubmitting ? (
              <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
            ) : 'ENVIAR PARA APROVAÇÃO'}
          </button>
          <button type="button" onClick={onCancel} className="text-gray-400 font-bold text-xs uppercase tracking-widest py-2">Voltar</button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
