  const [lastRegisteredOwner, setLastRegisteredOwner] = useState<BusinessOwner | null>(null);

  // Efeito para detectar Login Automático via Link (Link Mágico)
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const loginEmail = params.get('login');

    if (loginEmail) {
      // Simulação de Login: Se o link tiver ?login=email, damos acesso ao painel
      // Em uma app real, aqui haveria uma verificação de token de segurança
      const mockOwner: BusinessOwner = {
        fullName: "Usuário Aprovado",
        companyName: "Posto Autorizado",
        email: loginEmail,
        phone: "900000000",
        nif: "000000000",
        biNumber: "000000000",
        neighborhood: "Centro"
      };

      setLoggedInOwner(mockOwner);
      setCurrentView('business');

      // Limpar a URL para não ficar com o e-mail exposto
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, []);

  const handleUpdateStation = (stationId: string, gasoline: FuelStatus, diesel: FuelStatus) => {
    setStations(prev => prev.map(s => 
      s.id === stationId 
        ? { ...s, gasolineStatus: gasoline, dieselStatus: diesel, lastUpdated: new Date().toISOString() } 
        : s
    ));
  };

  const handleRegister = (data: BusinessOwner) => {
    setLastRegisteredOwner(data);
    setCurrentView('pending');
  };

  const handleLogout = () => {
    setLoggedInOwner(null);
    setCurrentView('user');
  };

